function check_increaseLiquidity_unauthorized(address caller, uint256 tokenId, uint256 amount0, uint256 amount1) public {
    vm.assume(caller != address(0));
    vm.assume(nfpm.ownerOf(tokenId) != caller);
    vm.assume(nfpm.getApproved(tokenId) != caller);
    vm.assume(!nfpm.isApprovedForAll(nfpm.ownerOf(tokenId), caller));

    INonfungiblePositionManager.IncreaseLiquidityParams memory params = INonfungiblePositionManager.IncreaseLiquidityParams({
        tokenId: tokenId,
        amount0Desired: amount0,
        amount1Desired: amount1,
        amount0Min: 0,
        amount1Min: 0,
        deadline: block.timestamp + 1
    });

    vm.prank(caller);
    try nfpm.increaseLiquidity(params) {
        assert(false); // Should have reverted
    } catch {
        // Expected revert
    }
}
